SELECT
    COALESCE(SUM(md.amount), 0) + COALESCE(SUM(ed.amount), 0) AS totalExpense,
    COUNT(CASE WHEN cr.record_type_id = (SELECT id FROM public.codes WHERE group_code = 'RECORD_TYPE' AND code = 'MEDICAL') THEN 1 END) AS medicalCount,
    (
        SELECT COUNT(*)
        FROM public.care_record_medical_details md2
        JOIN public.care_records cr2 ON md2.care_record_id = cr2.id
        WHERE cr2.user_id = #{userId}
        AND cr2.dog_id = #{dogId}
        -- 필터 기간 내의 기록이면서
        AND cr2.record_date BETWEEN #{startDate} AND #{endDate}
        -- 오늘 날짜가 복약 기간에 포함되어야 함 (현재 진행 중)
        AND md2.medication_start_date <= #{today}
        -- 종료일(시작일 + 일수)이 오늘보다 커야 함 (오늘까지는 포함, 내일부터는 제외)
        AND (md2.medication_start_date + (md2.medication_days || ' days')::interval) > #{today}::timestamp
        AND md2.is_medication_completed = false
    ) AS activeMedicationCount,
    (
        SELECT COUNT(*)
        FROM public.schedules s
        JOIN public.dogs d2 ON s.dog_id = d2.id
        WHERE d2.user_id = #{userId}
        AND s.dog_id = #{dogId}
        AND s.schedule_date BETWEEN #{startDate} AND #{endDate}
        AND s.schedule_date >= #{today}
    ) AS upcomingScheduleCount
FROM public.care_records cr
LEFT JOIN public.care_record_medical_details md ON cr.id = md.care_record_id
LEFT JOIN public.care_record_expense_details ed ON cr.id = ed.care_record_id
WHERE cr.user_id = #{userId}
AND cr.dog_id = #{dogId}
AND cr.record_date BETWEEN #{startDate} AND #{endDate}

WITH category_totals AS ( SELECT ed.category_id AS categoryId, COALESCE(c.code_name, '기타') AS categoryName, SUM(ed.amount) AS amount FROM public.care_record_expense_details ed JOIN public.care_records cr ON ed.care_record_id = cr.id LEFT JOIN public.codes c ON ed.category_id = c.id WHERE cr.user_id = #{userId}
AND cr.dog_id = #{dogId}
AND cr.record_date BETWEEN #{startDate} AND #{endDate} GROUP BY ed.category_id, c.code_name ) SELECT categoryId, categoryName, amount, CASE WHEN SUM(amount) OVER() > 0 THEN ROUND((amount * 100.0) / SUM(amount) OVER(), 1) ELSE 0 END AS percentage FROM category_totals ORDER BY amount DESC

SELECT COALESCE(SUM(md.amount), 0)
FROM public.care_record_medical_details md
JOIN public.care_records cr ON md.care_record_id = cr.id
JOIN public.codes c ON cr.record_type_id = c.id
WHERE cr.user_id = #{userId}
AND c.group_code = 'RECORD_TYPE' AND c.code = 'MEDICAL'

    AND cr.dog_id = #{dogId}

AND cr.record_date BETWEEN #{startDate} AND #{endDate}
